const items = $input.all();

const newVehicles = [];
const expiring = [];
const sold = [];

for (const item of items) {
  const cat = item.json.category;
  const vehicles = item.json.vehicles;
  if (!vehicles) continue;
  if (cat === "new") newVehicles.push(...vehicles);
  if (cat === "expiring") expiring.push(...vehicles);
  if (cat === "sold") sold.push(...vehicles);
}

const total = newVehicles.length + expiring.length + sold.length;
if (total === 0) {
  return [{ json: { send_email: false, reason: "nothing actionable" } }];
}

const landingBase = "https://ad-pilot.ai/marketplace?id=";

let html = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 600px; margin: 0 auto; background: #ffffff;">
  <div style="background: linear-gradient(135deg, #4f46e5, #7c3aed); color: white; padding: 16px 24px; border-radius: 8px 8px 0 0;">
    <h1 style="margin: 0; font-size: 18px; font-weight: 600;">Marketplace Update</h1>
  </div>
  <div style="padding: 24px; border: 1px solid #e5e7eb; border-top: none; border-radius: 0 0 8px 8px;">
    <p style="font-size: 15px; color: #333; margin: 0 0 20px 0; line-height: 1.5;">
      Good morning, Shad! Here are the vehicles we recommend posting to Marketplace today. Click the button next to each one to get started.
    </p>`;

if (newVehicles.length > 0) {
  html += `<h2 style="color: #111; font-size: 14px; text-transform: uppercase; letter-spacing: 0.5px; margin: 0 0 16px 0; padding-bottom: 8px; border-bottom: 2px solid #4f46e5;">New Vehicles Ready to Post (${newVehicles.length})</h2>`;

  for (const v of newVehicles) {
    const price = v.price ? "$" + Number(v.price).toLocaleString() : "";
    const mileage = v.mileage ? Number(v.mileage).toLocaleString() + " mi" : "";
    const photos = v.photo_count || 0;

    html += `
    <table cellpadding="0" cellspacing="0" border="0" width="100%" style="margin-bottom: 16px; border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">
      <tr>
        <td width="120" style="vertical-align: top; padding: 0;">`;

    if (v.hero_image_url) {
      html += `<img src="${v.hero_image_url}" width="120" height="90" style="display: block; object-fit: cover;" alt="${v.year} ${v.make} ${v.model}" />`;
    }

    html += `</td>
        <td style="vertical-align: top; padding: 12px 16px;">
          <div style="font-size: 15px; font-weight: 600; color: #111; margin-bottom: 4px;">${v.year} ${v.make} ${v.model}</div>
          <div style="font-size: 13px; color: #666; margin-bottom: 4px;">
            <span style="color: #4f46e5; font-weight: 700;">${price}</span>`;

    if (mileage) html += ` &middot; ${mileage}`;
    if (photos > 0) html += ` &middot; ${photos} photos`;

    html += `</div>
          <div style="font-size: 13px; color: #666; margin-bottom: 8px;">${v.exterior_color || ""}</div>
          <a href="${landingBase}${v.stock_number}" style="display: inline-block; padding: 6px 16px; background: #4f46e5; color: #ffffff; text-decoration: none; border-radius: 6px; font-size: 13px; font-weight: 600;">Post to Marketplace</a>
        </td>
      </tr>
    </table>`;
  }
}

if (expiring.length > 0) {
  html += `<h2 style="color: #111; font-size: 14px; text-transform: uppercase; letter-spacing: 0.5px; margin: 24px 0 16px 0; padding-bottom: 8px; border-bottom: 2px solid #f59e0b;">Expiring Soon (${expiring.length})</h2>`;

  for (const v of expiring) {
    const expDate = new Date(v.expires_at).toLocaleDateString("en-US", { month: "short", day: "numeric" });
    html += `
    <table cellpadding="0" cellspacing="0" border="0" width="100%" style="margin-bottom: 12px; border: 1px solid #fcd34d; border-radius: 8px; overflow: hidden; background: #fffbeb;">
      <tr>
        <td style="padding: 12px 16px;">
          <div style="font-size: 14px; font-weight: 600; color: #111;">${v.year} ${v.make} ${v.model}</div>
          <div style="font-size: 13px; color: #92400e; margin: 4px 0 8px;">Expires ${expDate}</div>
          <a href="${landingBase}${v.vehicle_id}" style="display: inline-block; padding: 6px 16px; background: #f59e0b; color: #ffffff; text-decoration: none; border-radius: 6px; font-size: 13px; font-weight: 600;">Renew Listing</a>
        </td>
      </tr>
    </table>`;
  }
}

if (sold.length > 0) {
  html += `<h2 style="color: #111; font-size: 14px; text-transform: uppercase; letter-spacing: 0.5px; margin: 24px 0 16px 0; padding-bottom: 8px; border-bottom: 2px solid #ef4444;">Sold — Remove from Marketplace (${sold.length})</h2>`;

  for (const v of sold) {
    html += `
    <table cellpadding="0" cellspacing="0" border="0" width="100%" style="margin-bottom: 12px; border: 1px solid #fca5a5; border-radius: 8px; overflow: hidden; background: #fef2f2;">
      <tr>
        <td style="padding: 12px 16px;">
          <div style="font-size: 14px; font-weight: 600; color: #111;">Vehicle ${v.vehicle_id}</div>`;
    if (v.fb_listing_url) {
      html += `<div style="margin: 4px 0;"><a href="${v.fb_listing_url}" style="color: #ef4444; font-size: 13px;">View Listing &rarr;</a></div>`;
    }
    html += `<div style="font-size: 13px; color: #991b1b;">No longer in inventory — please remove</div>
        </td>
      </tr>
    </table>`;
  }
}

html += `
    <div style="margin-top: 24px; padding-top: 16px; border-top: 1px solid #e5e7eb; font-size: 13px; color: #999; line-height: 1.5;">
      <strong style="color: #666;">Tips:</strong> Post 3-5 vehicles per day for best results. Space them out through the day. The extension fills everything automatically — just review and hit Publish!
    </div>
    <div style="margin-top: 12px; text-align: center; font-size: 11px; color: #bbb;">
      Powered by Ad Pilot
    </div>
  </div>
</div>`;

const subject = [];
if (newVehicles.length) subject.push(newVehicles.length + " new");
if (expiring.length) subject.push(expiring.length + " expiring");
if (sold.length) subject.push(sold.length + " sold");

return [{
  json: {
    send_email: true,
    subject: "Marketplace: " + subject.join(", "),
    html: html,
    new_count: newVehicles.length,
    expiring_count: expiring.length,
    sold_count: sold.length
  }
}];

